<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">MODULE_AUTHOR</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Your Name &lt;email@example.com&gt;&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
